mapper.select:
select b.pbom_id pbomId, b.pbom_code pbomCode, b.pbom_name pbomName, b.product_id productId,
	p.product_code productCode, p.product_name productName, b.version, b.status,
	b.create_by createBy, b.create_time createTime, b.update_by updateBy, b.update_time updateTime, b.remark
from mom_pbom b left join (
	select material_id product_id, material_code product_code, material_name product_name from mom_material where (material_type = 'product' or category_id in (select category_id from mom_material_category where category_code = 'FG' or category_name = '成品'))
) p on b.product_id = p.product_id

	and b.pbom_code like concat('%', #{pbomCode}, '%')
	and b.pbom_name like concat('%', #{pbomName}, '%')
	and b.product_id = #{productId}
	and b.status = #{status}

order by b.pbom_id desc

select b.pbom_id pbomId, b.pbom_code pbomCode, b.pbom_name pbomName, b.product_id productId,
	p.product_code productCode, p.product_name productName, b.version, b.status, b.remark
from mom_pbom b left join (
	select material_id product_id, material_code product_code, material_name product_name from mom_material where (material_type = 'product' or category_id in (select category_id from mom_material_category where category_code = 'FG' or category_name = '成品'))
) p on b.product_id = p.product_id
where b.pbom_id = #{pbomId}

select b.pbom_id pbomId, b.pbom_code pbomCode, b.pbom_name pbomName, b.product_id productId,
	p.product_code productCode, p.product_name productName, b.version, b.status, b.remark
from mom_pbom b left join (
	select material_id product_id, material_code product_code, material_name product_name from mom_material where (material_type = 'product' or category_id in (select category_id from mom_material_category where category_code = 'FG' or category_name = '成品'))
) p on b.product_id = p.product_id
where b.pbom_code = #{pbomCode}

mapper.update:
update mom_pbom
pbom_code = #{pbomCode}, pbom_name = #{pbomName}, product_id = #{productId}, version = #{version}, status = #{status}, remark = #{remark}, update_by = #{updateBy}, update_time = CURRENT_TIMESTAMP
where pbom_id = #{pbomId}

update mom_pbom_item
parent_item_id = #{parentItemId}, material_id = #{materialId}, resource_id = #{resourceId}, item_seq = #{itemSeq}, quantity = #{quantity}, status = #{status}, remark = #{remark}, update_by = #{updateBy}, update_time = CURRENT_TIMESTAMP
where item_id = #{itemId}

