mapper.select:
select category_id categoryId, category_code categoryCode, category_name categoryName, device_type deviceType, status, create_time createTime, remark from mom_device_category
and category_code like concat('%', #{categoryCode}, '%') and category_name like concat('%', #{categoryName}, '%') and device_type = #{deviceType} and status = #{status}
order by category_id desc

