mapper.select:
select d.device_id deviceId, d.device_code deviceCode, d.device_name deviceName, d.category_id categoryId, c.category_name categoryName, c.device_type deviceType, d.resource_id resourceId, r.resource_name resourceName, d.ip_address ipAddress, d.port, d.status, d.runtime_data runtimeData, d.last_connect_time lastConnectTime, d.remark from mom_device d left join mom_device_category c on d.category_id = c.category_id left join mom_resource r on d.resource_id = r.resource_id
and d.device_code like concat('%', #{deviceCode}, '%') and d.device_name like concat('%', #{deviceName}, '%') and c.device_type = #{deviceType} and d.resource_id = #{resourceId} and d.status = #{status}
order by d.device_id desc

mapper.update:
update mom_device
device_code = #{deviceCode}, device_name = #{deviceName}, category_id = #{categoryId}, resource_id = #{resourceId}, ip_address = #{ipAddress}, port = #{port}, status = #{status}, remark = #{remark}, update_by = #{updateBy}, update_time = CURRENT_TIMESTAMP
where device_id = #{deviceId}

update mom_device set status = #{status}, runtime_data = #{runtimeData}, last_connect_time = CURRENT_TIMESTAMP,
	update_by = #{updateBy}, update_time = CURRENT_TIMESTAMP
where device_id = #{deviceId}

mapper.select:
select l.log_id logId, l.user_name userName, l.rfid_card rfidCard, l.resource_id resourceId, r.resource_name resourceName, l.duty_type dutyType, l.status, l.create_time createTime, l.remark from mom_duty_log l left join mom_resource r on l.resource_id = r.resource_id
and l.user_name like concat('%', #{userName}, '%') and l.resource_id = #{resourceId} and l.status = #{status}
order by l.log_id desc
